+fn clamp_nanos_f64(nanos: f64) -> u64 {
+    if !nanos.is_finite() || nanos <= 0.0 {
+        return 0;
+    }
+    if nanos >= u64::MAX as f64 {
+        return u64::MAX;
+    }
+    nanos as u64
